#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *a = (long long*)malloc(N*sizeof(long long));
        long long *left = (long long*)malloc(N*sizeof(long long));
        long long *right = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld", &a[i]);
        // left pass
        left[0]=a[0];
        for(int i=1;i<N;i++){
            long long cand = left[i-1]+1;
            left[i] = a[i] < cand ? a[i] : cand;
        }
        // right pass
        right[N-1]=a[N-1];
        for(int i=N-2;i>=0;i--){
            long long cand = right[i+1]+1;
            right[i] = a[i] < cand ? a[i] : cand;
        }
        // output answer
        for(int i=0;i<N;i++){
            long long ans = left[i] < right[i] ? left[i] : right[i];
            printf("%lld", ans);
            if(i+1<N) printf(" ");
        }
        printf("\n");
        free(a); free(left); free(right);
    }
    return 0;
}

